-- ----------------------------------------------------------------------------
-- vw_users: Login identities for the demo (stub auth).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_users WITH (security_invoker = ON) AS
SELECT
  t.user_id,
  t.name,
  t.email,
  t.role,                                                                       -- trainer | client | admin
  t.display_name
FROM users t;

-- ----------------------------------------------------------------------------
-- vw_trainers: Personal trainers who log sessions and bill clients.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_trainers WITH (security_invoker = ON) AS
SELECT
  t.trainer_id,
  t.name,
  t.email,
  t.full_name,
  t.hourly_rate,                                                                -- Default $/hour charged to clients.
  calc_trainers_total_sessions(t.trainer_id) AS total_sessions,
  calc_trainers_total_billed(t.trainer_id) AS total_billed,
  calc_trainers_total_outstanding(t.trainer_id) AS total_outstanding
FROM trainers t;

-- ----------------------------------------------------------------------------
-- vw_clients: Trainer's clients.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_clients WITH (security_invoker = ON) AS
SELECT
  t.client_id,
  t.name,
  t.email,
  t.full_name,
  t.trainer,
  calc_clients_trainer_name(t.client_id) AS trainer_name,
  calc_clients_trainer_email(t.client_id) AS trainer_email,
  calc_clients_trainer_hourly_rate(t.client_id) AS trainer_hourly_rate,
  calc_clients_session_count(t.client_id) AS session_count,
  calc_clients_total_invoiced(t.client_id) AS total_invoiced,
  calc_clients_outstanding_balance(t.client_id) AS outstanding_balance,
  calc_clients_overdue_count(t.client_id) AS overdue_count,
  calc_clients_status(t.client_id) AS status
FROM clients t;

-- ----------------------------------------------------------------------------
-- vw_invoices: An invoice bundles one or more sessions billed to a client.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_invoices WITH (security_invoker = ON) AS
SELECT
  t.invoice_id,
  t.name,
  t.client,
  calc_invoices_client_name(t.invoice_id) AS client_name,
  calc_invoices_client_email(t.invoice_id) AS client_email,
  calc_invoices_trainer(t.invoice_id) AS trainer,
  calc_invoices_trainer_name(t.invoice_id) AS trainer_name,
  t.issue_date,
  t.due_date,
  t.tax_rate,                                                                   -- Decimal (e.g. 0.08 = 8%).
  t.discount_amount,
  t.paid_amount,
  calc_invoices_subtotal(t.invoice_id) AS subtotal,
  calc_invoices_tax_amount(t.invoice_id) AS tax_amount,
  calc_invoices_grace_days(t.invoice_id) AS grace_days,                         -- Grace period (in days) after the DueDate before an invoice is considered late.
  calc_invoices_days_since_due_date(t.invoice_id) AS days_since_due_date,       -- Raw whole days from DueDate to now (can be negative if not yet due).
  calc_invoices_days_past_due(t.invoice_id) AS days_past_due,                   -- Whole days past DueDate after the GraceDays window; 0 inside the grace window.
  calc_invoices_late_fee(t.invoice_id) AS late_fee,                             -- $15 flat fee once an invoice is past the 45-day grace period.
  calc_invoices_total(t.invoice_id) AS total,
  calc_invoices_balance(t.invoice_id) AS balance,
  calc_invoices_is_paid(t.invoice_id) AS is_paid,
  calc_invoices_is_overdue(t.invoice_id) AS is_overdue,                         -- True only after the GraceDays window has elapsed.
  calc_invoices_status(t.invoice_id) AS status
FROM invoices t;

-- ----------------------------------------------------------------------------
-- vw_sessions: A logged training session. The atomic line item that rolls up into an invoice.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_sessions WITH (security_invoker = ON) AS
SELECT
  t.session_id,
  t.name,
  t.client,
  calc_sessions_client_name(t.session_id) AS client_name,
  calc_sessions_trainer(t.session_id) AS trainer,
  calc_sessions_client_hourly_rate(t.session_id) AS client_hourly_rate,
  t.session_date,
  t.duration_hours,
  t.rate_override,                                                              -- If > 0, overrides the trainer's HourlyRate for this session.
  t.notes,
  calc_sessions_effective_rate(t.session_id) AS effective_rate,
  calc_sessions_line_total(t.session_id) AS line_total,
  t.invoice,
  calc_sessions_invoice_name(t.session_id) AS invoice_name,
  calc_sessions_is_billed(t.session_id) AS is_billed
FROM sessions t;

